from fractions import Fraction
# Q exponents in epsilon: Q=(eps^-1, eps^4, eps^-1, eps^0)
q=[-1,4,-1,0]
def mono_exp(k,j,l):
    # j product Q1..Qj; (j+1..l)^((k-j)/(l-j)), using 1-indexed arrays
    return sum(q[:j]) + Fraction(k-j,l-j)*sum(q[j:l])
for k in [2,3]:
    rows=[]
    for j in range(k):
        for l in range(k,5):
            if j<k<=l:
                rows.append((k,j,l,mono_exp(k,j,l)))
    print(rows)
